module top_module(
    input [2:0] In, 
    output reg [7:0] input_data 
);always @ (In)
begin
    case (In)
        3'b000:
            input_data = 8'd1;
        3'b001:
            input_data = 8'd2;
        3'b010:
            input_data = 8'd4;
        3'b011:
            input_data = 8'd8;
        3'b100:
            input_data = 8'd16;
        3'b101:
            input_data = 8'd32;
        3'b110:
            input_data = 8'd64;
        3'b111:
            input_data = 8'd128;
        default:
            input_data = 8'd0;
    endcase
end
endmodule
